(() => {
    'use strict';

    /* ── NAVIGATION ───────────────────── */
    const COOKIE_NAME = 'sidai_cookie_consent';
    const COOKIE_MAX_AGE = 60 * 60 * 24 * 180;

    const state = {
        lenis: null,
    };

    const qs = (selector, scope = document) => scope.querySelector(selector);
    const qsa = (selector, scope = document) => Array.from(scope.querySelectorAll(selector));

    const onReady = (callback) => {
        if (document.readyState === 'loading') {
            document.addEventListener('DOMContentLoaded', callback, { once: true });
            return;
        }

        callback();
    };

    const canUseGSAP = () => typeof window.gsap !== 'undefined';

    /* ── ANIMATIONS ────────────────────── */
    const registerGSAP = () => {
        if (!canUseGSAP()) {
            return;
        }

        const { gsap, ScrollTrigger, TextPlugin, ScrollToPlugin } = window;

        if (ScrollTrigger) {
            gsap.registerPlugin(ScrollTrigger);
        }
        if (TextPlugin) {
            gsap.registerPlugin(TextPlugin);
        }
        if (ScrollToPlugin) {
            gsap.registerPlugin(ScrollToPlugin);
        }
    };

    /* ── SMOOTH SCROLL ─────────────────── */
    // Keeps scrolling fluid while preserving native browser behavior fallback.
    const initLenis = () => {
        if (typeof window.Lenis === 'undefined') {
            return;
        }

        state.lenis = new window.Lenis({
            duration: 1.1,
            smoothWheel: true,
            wheelMultiplier: 0.95,
            touchMultiplier: 1.25,
        });

        const raf = (time) => {
            state.lenis.raf(time);
            window.requestAnimationFrame(raf);
        };

        window.requestAnimationFrame(raf);
    };

    /* ── ANIMATIONS ────────────────────── */
    const initAOS = () => {
        if (typeof window.AOS === 'undefined') {
            return;
        }

        window.AOS.init({
            once: true,
            duration: 850,
            easing: 'ease-out-cubic',
            offset: 30,
        });
    };

    /* ── BOOKING FORM ──────────────────── */
    // Booking submit behavior is intentionally handled in page-level inline scripts.
    const initFlatpickr = () => {
        if (typeof window.flatpickr === 'undefined') {
            return;
        }

        qsa('.js-flatpickr').forEach((input) => {
            window.flatpickr(input, {
                minDate: 'today',
                dateFormat: 'Y-m-d',
                disableMobile: true,
            });
        });
    };

    /* ── ANIMATIONS ────────────────────── */
    const splitTextToSpans = (element) => {
        const text = (element.textContent || '').trim();
        if (text === '') {
            return [];
        }

        element.innerHTML = '';
        return [...text].map((character) => {
            const span = document.createElement('span');
            span.textContent = character === ' ' ? '\u00A0' : character;
            span.style.display = 'inline-block';
            span.style.opacity = '0';
            span.style.transform = 'translateY(8px)';
            element.appendChild(span);
            return span;
        });
    };

    const hideLoaderFallback = () => {
        const loader = qs('#page-loader');
        if (!loader) {
            return;
        }

        loader.classList.add('is-hidden');
        window.setTimeout(() => {
            loader.remove();
        }, 650);
    };

    /* ── ANIMATIONS ────────────────────── */
    const initPageLoader = () => {
        const loader = qs('#page-loader');
        if (!loader) {
            return;
        }

        const logo = qs('.loader-logo', loader);
        const copy = qs('.loader-copy', loader);

        const closeLoader = () => {
            loader.classList.add('is-hidden');
            window.setTimeout(() => loader.remove(), 800);
        };

        if (!canUseGSAP() || !logo || !copy) {
            window.addEventListener('load', hideLoaderFallback, { once: true });
            return;
        }

        const logoLetters = splitTextToSpans(logo);
        const copyLetters = splitTextToSpans(copy);

        window.addEventListener('load', () => {
            const tl = window.gsap.timeline({ defaults: { ease: 'power3.out' } });
            tl
                .to(logoLetters, { opacity: 1, y: 0, stagger: 0.05, duration: 0.22 })
                .to(copyLetters, { opacity: 1, y: 0, stagger: 0.03, duration: 0.16 }, '-=0.15')
                .to(loader, { opacity: 0, duration: 0.45, delay: 0.8, onComplete: closeLoader });
        }, { once: true });

        window.setTimeout(() => {
            if (document.body.contains(loader)) {
                closeLoader();
            }
        }, 2500);
    };

    /* ── NAVIGATION ───────────────────── */
    const initNavScrollState = () => {
        const header = qs('#site-header');
        if (!header) {
            return;
        }

        const update = () => {
            header.classList.toggle('is-scrolled', window.scrollY > 16);
        };

        update();
        window.addEventListener('scroll', update, { passive: true });
    };

    /* ── NAVIGATION ───────────────────── */
    const initBackToTop = () => {
        const button = qs('#back-to-top');
        if (!button) {
            return;
        }

        button.addEventListener('click', (event) => {
            event.preventDefault();

            if (canUseGSAP() && window.ScrollToPlugin) {
                window.gsap.to(window, { duration: 0.8, scrollTo: { y: 0 }, ease: 'power2.out' });
                return;
            }

            window.scrollTo({ top: 0, behavior: 'smooth' });
        });
    };

    /* ── ANIMATIONS ────────────────────── */
    const initHeroParticles = () => {
        const particlesNode = qs('#hero-particles');
        if (!particlesNode || typeof window.particlesJS === 'undefined') {
            return;
        }

        window.particlesJS('hero-particles', {
            particles: {
                number: { value: 50, density: { enable: true, value_area: 800 } },
                color: { value: '#D4AF37' },
                shape: { type: 'circle' },
                opacity: { value: 0.45, random: true },
                size: { value: 2.8, random: true },
                line_linked: {
                    enable: true,
                    distance: 120,
                    color: '#D4AF37',
                    opacity: 0.22,
                    width: 1,
                },
                move: {
                    enable: true,
                    speed: 1.4,
                    direction: 'none',
                    random: false,
                    straight: false,
                    out_mode: 'out',
                },
            },
            interactivity: {
                detect_on: 'canvas',
                events: {
                    onhover: { enable: true, mode: 'repulse' },
                    onclick: { enable: true, mode: 'push' },
                    resize: true,
                },
                modes: {
                    repulse: { distance: 80, duration: 0.4 },
                    push: { particles_nb: 3 },
                },
            },
            retina_detect: true,
        });
    };

    /* ── ANIMATIONS ────────────────────── */
    const initHeroTypewriter = () => {
        const target = qs('#hero-typewriter');
        if (!target) {
            return;
        }

        const words = ['Weddings', 'Celebrations', 'Safari Escapes', 'Fine Dining'];

        if (canUseGSAP() && window.TextPlugin) {
            const tl = window.gsap.timeline({ repeat: -1 });
            target.textContent = '';

            words.forEach((word) => {
                tl.to(target, { duration: 0.9, text: word, ease: 'none' })
                    .to({}, { duration: 0.9 })
                    .to(target, { duration: 0.45, text: '', ease: 'none' });
            });

            return;
        }

        let index = 0;
        window.setInterval(() => {
            target.textContent = words[index];
            index = (index + 1) % words.length;
        }, 1800);
    };

    /* ── ANIMATIONS ────────────────────── */
    // Animates number counters only when elements enter the viewport.
    const initCounterAnimations = () => {
        const counters = qsa('[data-counter]');
        if (counters.length === 0) {
            return;
        }

        const renderCounter = (element, value, target, suffix, format) => {
            if (format === 'infinity') {
                element.textContent = value >= target ? '\u221E' : `${Math.floor(value)}+`;
                return;
            }

            element.textContent = `${Math.floor(value)}${suffix}`;
        };

        const animate = (element) => {
            const target = Number(element.dataset.counterTarget || '0');
            const suffix = element.dataset.counterSuffix || '';
            const format = element.dataset.counterFormat || 'number';

            if (canUseGSAP()) {
                const data = { value: 0 };
                window.gsap.to(data, {
                    value: target,
                    duration: 1.6,
                    ease: 'power2.out',
                    onUpdate: () => renderCounter(element, data.value, target, suffix, format),
                    onComplete: () => renderCounter(element, target, target, suffix, format),
                });
                return;
            }

            const startedAt = performance.now();
            const duration = 1400;

            const frame = (now) => {
                const progress = Math.min((now - startedAt) / duration, 1);
                const value = target * progress;
                renderCounter(element, value, target, suffix, format);
                if (progress < 1) {
                    window.requestAnimationFrame(frame);
                }
            };

            window.requestAnimationFrame(frame);
        };

        const observer = new IntersectionObserver((entries, obs) => {
            entries.forEach((entry) => {
                if (!entry.isIntersecting) {
                    return;
                }

                animate(entry.target);
                obs.unobserve(entry.target);
            });
        }, { threshold: 0.55 });

        counters.forEach((counter) => observer.observe(counter));
    };

    /* ── ANIMATIONS ────────────────────── */
    const initParallaxMedia = () => {
        const nodes = qsa('[data-parallax-speed]');
        if (nodes.length === 0) {
            return;
        }

        const update = () => {
            const viewportHeight = window.innerHeight || 1;
            nodes.forEach((node) => {
                const speed = Number(node.dataset.parallaxSpeed || '0');
                const rect = node.getBoundingClientRect();
                const offset = (rect.top - viewportHeight * 0.5) * speed * -0.2;
                node.style.transform = `translateY(${offset.toFixed(2)}px)`;
            });
        };

        update();
        window.addEventListener('scroll', update, { passive: true });
        window.addEventListener('resize', update);
    };

    /* ── GALLERY ───────────────────────── */
    const initImageRevealObserver = () => {
        const images = qsa('[data-reveal-image]');
        if (images.length === 0) {
            return;
        }

        images.forEach((image) => {
            image.style.opacity = '0';
            image.style.transform = 'translateY(16px)';
            image.style.transition = 'opacity 0.55s ease, transform 0.55s ease';
        });

        const observer = new IntersectionObserver((entries, obs) => {
            entries.forEach((entry) => {
                if (!entry.isIntersecting) {
                    return;
                }

                const node = entry.target;
                if (canUseGSAP()) {
                    window.gsap.to(node, { opacity: 1, y: 0, duration: 0.5, ease: 'power2.out' });
                } else {
                    node.style.opacity = '1';
                    node.style.transform = 'translateY(0)';
                }

                obs.unobserve(node);
            });
        }, { threshold: 0.2 });

        images.forEach((image) => observer.observe(image));
    };

    /* ── GALLERY ───────────────────────── */
    const initSwipers = () => {
        if (typeof window.Swiper === 'undefined') {
            return;
        }

        if (qs('[data-swiper-events]')) {
            new window.Swiper('.events-swiper', {
                slidesPerView: 1.08,
                spaceBetween: 18,
                loop: true,
                speed: 750,
                autoplay: {
                    delay: 3500,
                    disableOnInteraction: false,
                },
                pagination: {
                    el: '.events-swiper-pagination',
                    clickable: true,
                },
                breakpoints: {
                    640: { slidesPerView: 1.4 },
                    1024: { slidesPerView: 2.2 },
                },
            });
        }

        if (qs('[data-swiper-testimonials]')) {
            new window.Swiper('.testimonials-swiper', {
                slidesPerView: 1,
                spaceBetween: 18,
                loop: true,
                speed: 700,
                autoplay: {
                    delay: 4200,
                    disableOnInteraction: false,
                },
                pagination: {
                    el: '.testimonials-swiper-pagination',
                    clickable: true,
                },
                breakpoints: {
                    768: { slidesPerView: 2 },
                    1200: { slidesPerView: 3 },
                },
            });
        }
    };

    /* ── GALLERY ───────────────────────── */
    const initLightbox = () => {
        if (typeof window.GLightbox === 'undefined') {
            return;
        }

        window.GLightbox({
            selector: '.gallery-lightbox',
            touchNavigation: true,
            loop: true,
        });
    };

    const shouldHandleTransition = (link) => {
        if (!(link instanceof HTMLAnchorElement)) {
            return false;
        }

        if (link.classList.contains('gallery-lightbox') || link.hasAttribute('data-no-transition')) {
            return false;
        }

        const href = link.getAttribute('href') || '';
        if (href === '' || href.startsWith('#') || href.startsWith('mailto:') || href.startsWith('tel:')) {
            return false;
        }

        if (/\.(?:avif|gif|jpe?g|png|svg|webp|mp4|webm|mov)(?:[?#].*)?$/i.test(href)) {
            return false;
        }

        if (link.target && link.target !== '_self') {
            return false;
        }

        const url = new URL(href, window.location.href);
        return url.origin === window.location.origin;
    };

    /* ── NAVIGATION ───────────────────── */
    const initPageTransition = () => {
        const overlay = qs('#page-transition-overlay');
        if (!overlay) {
            return;
        }

        const animateIn = () => {
            if (canUseGSAP()) {
                window.gsap.to(overlay, { opacity: 0, duration: 0.45, pointerEvents: 'none' });
                return;
            }

            overlay.classList.remove('is-active');
        };

        const animateOut = (navigate) => {
            if (canUseGSAP()) {
                window.gsap.to(overlay, {
                    opacity: 1,
                    duration: 0.35,
                    pointerEvents: 'auto',
                    onComplete: navigate,
                });
                return;
            }

            overlay.classList.add('is-active');
            window.setTimeout(navigate, 250);
        };

        animateIn();

        document.addEventListener('click', (event) => {
            const link = event.target instanceof Element ? event.target.closest('a') : null;
            if (!shouldHandleTransition(link)) {
                return;
            }

            const url = new URL(link.href, window.location.href);
            if (url.href === window.location.href) {
                return;
            }

            event.preventDefault();
            animateOut(() => {
                window.location.href = url.href;
            });
        });
    };

    /* ── NAVIGATION ───────────────────── */
    const setCookie = (name, value, maxAge) => {
        document.cookie = `${name}=${encodeURIComponent(value)}; Max-Age=${maxAge}; Path=/; SameSite=Strict${window.location.protocol === 'https:' ? '; Secure' : ''}`;
    };

    const getCookie = (name) => {
        const parts = document.cookie.split(';').map((part) => part.trim());
        const match = parts.find((part) => part.startsWith(`${name}=`));
        return match ? decodeURIComponent(match.substring(name.length + 1)) : null;
    };

    const buildCookieBanner = () => {
        const wrapper = document.createElement('aside');
        wrapper.id = 'cookie-consent';
        wrapper.className = 'fixed inset-x-4 bottom-4 z-[80] rounded-2xl border border-gold/40 bg-night/95 p-4 text-cream shadow-2xl md:inset-x-auto md:right-6 md:w-[25rem]';
        wrapper.innerHTML = `
            <p class="font-semibold text-gold">Cookie Preferences</p>
            <p class="mt-2 text-sm text-cream/80">We use essential cookies to keep Sidai Resort secure and improve your experience.</p>
            <div class="mt-4 flex gap-2">
                <button type="button" data-cookie-accept class="flex-1 rounded-xl bg-gold px-3 py-2 text-sm font-semibold text-night">Accept</button>
                <button type="button" data-cookie-decline class="flex-1 rounded-xl border border-gold/40 px-3 py-2 text-sm font-semibold text-gold">Decline</button>
            </div>
        `;

        return wrapper;
    };

    /* ── NAVIGATION ───────────────────── */
    const initCookieConsent = () => {
        if (getCookie(COOKIE_NAME) !== null) {
            return;
        }

        const banner = buildCookieBanner();
        document.body.appendChild(banner);

        const close = (value) => {
            setCookie(COOKIE_NAME, value, COOKIE_MAX_AGE);

            if (canUseGSAP()) {
                window.gsap.to(banner, {
                    y: 20,
                    opacity: 0,
                    duration: 0.3,
                    onComplete: () => banner.remove(),
                });
                return;
            }

            banner.remove();
        };

        qs('[data-cookie-accept]', banner)?.addEventListener('click', () => close('accepted'));
        qs('[data-cookie-decline]', banner)?.addEventListener('click', () => close('declined'));
    };

    /* ── MENU TABS ─────────────────────── */
    // Menu tab logic is page-specific and kept inside the individual HTML pages.

    onReady(() => {
        registerGSAP();
        initLenis();
        initAOS();
        initFlatpickr();
        initPageLoader();
        initNavScrollState();
        initBackToTop();
        initHeroParticles();
        initHeroTypewriter();
        initCounterAnimations();
        initParallaxMedia();
        initImageRevealObserver();
        initSwipers();
        initLightbox();
        initPageTransition();
        initCookieConsent();
    });
})();
